CREATE TABLE news (
  id SERIAL PRIMARY KEY,
  title VARCHAR(300) NOT NULL,
  content TEXT NOT NULL,
  image_url VARCHAR(500) DEFAULT '',
  is_active BOOLEAN DEFAULT true,
  sort_order INT DEFAULT 0,
  created_at TIMESTAMP DEFAULT NOW(),
  updated_at TIMESTAMP DEFAULT NOW()
);

INSERT INTO news (title, content, image_url, sort_order) VALUES
(
  'Российские автовладельцы массово переходят на китайские автомобили',
  'По данным аналитического агентства «Автостат», в 2024 году доля китайских брендов на российском рынке превысила 55%, что стало историческим рекордом. Ещё несколько лет назад этот показатель не превышал 10%. Главными драйверами роста стали такие марки, как Haval, Chery, Geely, OMODA и Jaecoo. Покупатели отмечают привлекательное соотношение цены и оснащённости: за сумму, которую раньше просили за среднеклассовый европейский автомобиль, теперь можно купить китайский кроссовер с полным пакетом опций — панорамной крышей, подогревом всех сидений, большим сенсорным экраном и системами помощи водителю.

Дилеры фиксируют рекордные очереди на популярные модели. В частности, ожидание Haval F7 и Chery Tiggo 8 Pro в ряде регионов достигает трёх-четырёх месяцев. Производители реагируют на спрос: OMODA открыла новые дилерские центры в 15 городах, а Geely запустила локализованное производство на заводе в Беларуси для поставок на российский рынок.

Вместе с тем эксперты предупреждают о росте стоимости обслуживания. Оригинальные запчасти для китайских автомобилей пока в дефиците, и многие владельцы вынуждены ждать по несколько недель. Специалисты рекомендуют выбирать сервисные центры с опытом работы именно с китайскими марками, поскольку диагностическое оборудование для них существенно отличается от привычного.',
  'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=600&q=80',
  1
),
(
  'Новые правила техосмотра в России: что изменится с 2025 года',
  'Министерство транспорта России подготовило масштабные поправки к порядку прохождения технического осмотра транспортных средств. Согласно проекту, который планируется ввести в действие с 1 марта 2025 года, список обязательных проверок существенно расширится. В частности, операторы ТО будут обязаны проверять работу систем активной безопасности — ABS, ESP и систем автоматического экстренного торможения, которые сейчас во многих пунктах попросту игнорируются.

Кроме того, ужесточатся требования к состоянию шин: допустимый остаток протектора для летней резины составит не менее 1,6 мм, а для зимней — не менее 4 мм. Отдельное внимание будет уделено световому оборудованию: угол наклона фар будет измеряться приборами, а не визуально. Ещё одно новшество — обязательная проверка уровня выхлопных газов по расширенному перечню параметров.

Штрафы за езду без действующего ТО планируется увеличить с нынешних 2 000 рублей до 5 000 рублей. Для повторных нарушений предусматривается лишение права управления транспортным средством сроком до одного месяца. Автовладельцам рекомендуется заблаговременно проверить состояние автомобиля и устранить неисправности, пока новые правила не вступили в силу.',
  'https://images.unsplash.com/photo-1486262715619-67b85e0b08d3?w=600&q=80',
  2
),
(
  'Электромобили в России: зарядная инфраструктура растёт, но проблемы остаются',
  'По итогам 2024 года количество публичных зарядных станций для электромобилей в России превысило 12 000 единиц, увеличившись за год вдвое. Основной прирост обеспечили федеральные трассы М-4 «Дон», М-11 «Нева» и М-12 «Восток», где зарядные станции теперь расположены с интервалом не более 80 километров. В крупных городах — Москве, Санкт-Петербурге, Казани и Екатеринбурге — зарядные точки появились на парковках торговых центров, жилых комплексов и у офисных зданий.

Тем не менее владельцы электромобилей по-прежнему сталкиваются с серьёзными трудностями. Значительная часть станций установлена операторами, использующими разные стандарты разъёмов и приложения для оплаты, что создаёт неудобства в поездках. Кроме того, реальная мощность зарядки нередко оказывается ниже заявленной: из-за устаревшего сетевого оборудования быстрая зарядка нередко работает в «медленном» режиме.

Продажи электромобилей в России в 2024 году составили около 45 000 единиц, из которых более 70% пришлось на китайские марки — BYD, Li Auto и Zeekr. Самой популярной моделью стал BYD Seal, привлёкший покупателей запасом хода более 500 км и богатым оснащением. Правительство прорабатывает субсидии на покупку электромобилей отечественного производства, однако конкретные параметры программы пока не утверждены.',
  'https://images.unsplash.com/photo-1593941707882-a5bba14938c7?w=600&q=80',
  3
),
(
  'Как правильно подготовить автомобиль к летнему сезону',
  'С наступлением тёплого времени года каждый автовладелец сталкивается с необходимостью провести сезонное обслуживание автомобиля. Специалисты называют несколько ключевых пунктов, которые нельзя игнорировать. Первое и самое очевидное — смена резины. Летние шины обеспечивают значительно лучшее сцепление с тёплым асфальтом и существенно короче тормозной путь по сравнению с зимними при температурах выше +7 градусов.

Второй важный момент — проверка тормозной системы. За зиму колодки и диски изнашиваются интенсивнее из-за перепадов температур, реагентов и загрязнений. Тормоза следует проверить визуально и при необходимости произвести замену. Третий пункт — кондиционер: если система не использовалась несколько месяцев, перед летним сезоном рекомендуется проверить уровень хладагента и при необходимости заправить систему.

Не менее важно проверить уровень и состояние всех технических жидкостей: охлаждающей, тормозной, рулевого усилителя и жидкости омывателя. Летом двигатель работает в условиях повышенных температур, поэтому состояние антифриза и радиатора особенно критично. Опытные мастера также советуют провести компьютерную диагностику, которая позволит выявить скрытые неисправности до того, как они обернутся серьёзной поломкой в дороге.',
  'https://images.unsplash.com/photo-1492144534655-ae79c964c9d7?w=600&q=80',
  4
);
